INSERT OR IGNORE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('Tera C-LW', '渔轮', '动力鼓轮', 'Tera C-LW', 'Tera C-LW 20', 'Tera C-LW – 是由Beluga生产的一系列动力辅助鼓轮。线轴主体由石墨和阳极氧化铝制成。它具有良好的防水性，因此非常适合在海水中使用。它的制动系统能够平滑地调节制动力，这使得它即使在高负荷下也能够稳定地运行。', '4.9:1', 0, '', '', 0, '20', '动力辅助鼓轮', '18.1kg', 0, '0.63', '', 0, '25', '', '', '', '≥31g', 0, '83.02', '12978.7', '104.7kg', 0, '💧');
